export type ParsedFundInvoiceInstruction<
  TProgram extends string = typeof FACTORIZE_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    investor: TAccountMetas[0];
    invoiceVault: TAccountMetas[1];
    invoiceVaultAta: TAccountMetas[2];
    usdcInvestorAta: TAccountMetas[3];
    sharesInvestorAta: TAccountMetas[4];
    shares: TAccountMetas[5];
    usdcMint: TAccountMetas[6];
    config: TAccountMetas[7];
    systemProgram: TAccountMetas[8];
    tokenProgram: TAccountMetas[9];
    associatedTokenProgram: TAccountMetas[10];
  };
  data: FundInvoiceInstructionData;
};

export function parseFundInvoiceInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedFundInvoiceInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 11) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 11,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      investor: getNextAccount(),
      invoiceVault: getNextAccount(),
      invoiceVaultAta: getNextAccount(),
      usdcInvestorAta: getNextAccount(),
      sharesInvestorAta: getNextAccount(),
      shares: getNextAccount(),
      usdcMint: getNextAccount(),
      config: getNextAccount(),
      systemProgram: getNextAccount(),
      tokenProgram: getNextAccount(),
      associatedTokenProgram: getNextAccount(),
    },
    data: getFundInvoiceInstructionDataDecoder().decode(instruction.data),
  };
}
